import{_ as r,o as t,c as n,j as e,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"6、恋人【VI】","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/6、恋人【VI】.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/6、恋人【VI】.md"}'),o={name:"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/6、恋人【VI】.md"};function d(_,a,i,l,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"_6、恋人【vi】",tabindex:"-1"},[p("6、恋人【VI】 "),e("a",{class:"header-anchor",href:"#_6、恋人【vi】","aria-label":'Permalink to "6、恋人【VI】"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),s('<h1 id="恋人" tabindex="-1">恋人 <a class="header-anchor" href="#恋人" aria-label="Permalink to &quot;恋人&quot;">​</a></h1><p>恋人</p><p>S+9600<br> 替身外貌：<br> 恋人是一种长相如同金色寄生虫一般的超小型替身，生有一对圆形的机械双眼以及昆虫口器般的嘴，双手为钳子，臀部生有两根尾巴般的结构。</p><p>替身数据：<br> 破坏力E<br> 速度D（闪避防御）<br> 射程A<br> 持续力A<br> 精密动作性D<br> 成长性E</p><p>替身对应主属性：耐力</p><p>替身能力：<br> 超远射程：恋人的射程分为能力发动射程和能力作用射程，恋人的【寄生】能力只能在【耐力×10】米内发动，在【寄生】成功后能力作用范围提升至【耐力×200】米。</p><p>寄生：恋人是一种体型十分微小的替身，因此能够潜入他人的体内，直接入侵大脑等重要部位并控制神经，以一个标准动作控制恋人寄生到目标身上，目标以强韧豁免对替身使者的替身使用检定，不造成伤害，对抗失败会被恋人寄生，恋人一旦在他人体内寄生，则拥有恋人的替身使者承受任何感觉都会加倍反馈到被本体身上。<br> 替身使者因任何情况受到实际伤害后，记录这个实际伤害值。恋人会将这个数值乘3倍后的同类型伤害施加在被寄生的目标身上，持续至脱离替身作用射程、恋人更换寄生对象、拥有恋人的替身使者死亡，视为S级创伤来源的支配效果。</p><p>细胞改造：恋人还具备改造人体细胞的能力，可以利用细胞制造出无数个自己的分身，也能将细胞制造成一层拟态外壳披在自己身上以伪装成其他细胞大小的外貌，这意味着当他人检视自身身体状况，可能很难以分辨恋人与正常细胞的区别。具备B级及以上侦测等级、具备透视的感知方式可以用识破伪装为目的的调查检定来对抗你的【决心+隐秘+伪装】，若成功可区分恋人与身体细胞的区别，这视为A级变形来源的伪装效果。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const V=r(o,[["render",d]]);export{f as __pageData,V as default};
